const COLORS = {
  'info': blueberry,
  'warning': mango,
  'success': mint,
  'successDark': darkMint,
  'danger': cherryLight,
  'gray4': gray4,
  'gray3': gray3,
  'gray2': gray2,
  'white': brandWhite,
  'black': brandBlack,
  'purple': brandPurple,
  'highlight': brandHighlight,
  'darkBlueberry': darkBlueberry,
  'darkMango': darkMango,
}

const useStyles = createThemedStyles(theme => ({
  block: {
    display: 'block',
  },
  main: {
    color: theme.fgMain,
  },
  muted: {
    color: theme.fgMuted,
  },
  inline: {
    position: 'relative',
    verticalAlign: 'middle',
    margin: '-0.25em 0.25em 0',
  },
}))

type IconStroke = keyof typeof STROKES
type IconColor = keyof typeof COLORS | 'main' | 'muted'

interface IIcon {
  stroke: IconStroke
  color?: IconColor
  block?: boolean
  inline?: boolean
  size?: number
}

const Icon: React.FC<IIcon> = ({stroke, color, block, inline, size}) => {
  const classes = useStyles()
  return (
    <svg
      xmlns='http://www.w3.org/2000/svg'
      x='0px'
      y='0px'
      width={`${size * 16 || 16}px`}
      height={`${size * 16 || 16}px`}
      viewBox='0 0 16 16'
      fill={COLORS[color] || 'currentcolor'}
      className={combine(classes[color], block && classes.block, inline && classes.inline)}
    >
      <path fillRule='evenodd' d={STROKES[stroke]} />
    </svg>
  )
}

export {
  Icon,
  STROKES,
}

export type {
  IIcon,
  IconStroke,
  IconColor,
}
